import React, { useState, useEffect } from "react";
import "./Greeting.css";
import SocialMedia from "../../components/socialMedia/SocialMedia";
import Button from "../../components/button/Button";
import { stats } from "../../portfolio";

const roles = [
  "Lead Backend Engineer 💻",
  "GenAI Builder 🤖",
  "2× Co-Founder 💼"
];

// Lightweight typewriter — types a word, pauses, deletes, moves on.
// Uses Array.from so multi-byte emoji aren't split mid-surrogate.
function useTypewriter(words, typeSpeed = 90, deleteSpeed = 40, pause = 1500) {
  const [index, setIndex] = useState(0);
  const [subIndex, setSubIndex] = useState(0);
  const [deleting, setDeleting] = useState(false);

  useEffect(() => {
    const chars = Array.from(words[index % words.length]);

    if (!deleting && subIndex === chars.length) {
      const timeout = setTimeout(() => setDeleting(true), pause);
      return () => clearTimeout(timeout);
    }

    if (deleting && subIndex === 0) {
      setDeleting(false);
      setIndex(i => (i + 1) % words.length);
      return undefined;
    }

    const timeout = setTimeout(() => {
      setSubIndex(s => s + (deleting ? -1 : 1));
    }, deleting ? deleteSpeed : typeSpeed);
    return () => clearTimeout(timeout);
  }, [subIndex, deleting, index, words, typeSpeed, deleteSpeed, pause]);

  return Array.from(words[index % words.length]).slice(0, subIndex).join("");
}

export default function Greeting() {
  const typed = useTypewriter(roles);

  return (
    <div className="greet-main" id="greeting">
      <div className="greeting-main">
        <div className="greeting-text-div">
          <div>
            <h1 className="greeting-text">
              Hi There, I'm <span className="greeting-name">Shreyas</span>{" "}
              <span className="wave-emoji" role="img" aria-label="waving hand">
                👋
              </span>
            </h1>
            <p className="greeting-text-p subTitle greeting-typewriter">
              <span className="greeting-years">10+ years</span> ·{" "}
              <span className="typewriter-text">{typed}</span>
              <span className="typewriter-cursor">|</span>
            </p>

            <SocialMedia />
            <div className="greeting-location">
              <i className="fas fa-map-marker-alt"></i> Pune, Maharashtra
            </div>
            <div className="button-greeting-div">
              <Button text="Get in touch" href="#contact" />
            </div>
          </div>
        </div>
        <div className="greeting-image-div">
          <img alt="shreyas coding" src={require("../../assests/images/coding.svg")}></img>
        </div>
      </div>

      <div className="stat-strip">
        {stats.map(stat => (
          <div className="stat-chip" key={stat.value}>
            <span className="stat-value">{stat.value}</span>
            <span className="stat-label">{stat.label}</span>
          </div>
        ))}
      </div>
    </div>
  );
}
